## What to do
Create the core type definitions for the tree upload wizard. These are pure TypeScript types with no framework dependencies.

### Types to define:

```ts
export type ColumnMapping = {
  sourceColumn: string;
  targetField: string;
  transform?: (value: string) => string;
};

export type MappedRow = Record<string, string>;

export type OccurrenceInput = {
  scientificName: string;
  eventDate: string;
  decimalLatitude: number;
  decimalLongitude: number;
  basisOfRecord?: string;
  vernacularName?: string;
  recordedBy?: string;
  locality?: string;
  country?: string;
  countryCode?: string;
  occurrenceRemarks?: string;
  habitat?: string;
  samplingProtocol?: string;
  kingdom?: string;
};

export type FloraMeasurementBundle = {
  dbh?: string;
  totalHeight?: string;
  diameter?: string;  // maps to basalDiameter in PDS
  canopyCoverPercent?: string;
};

export type ValidatedRow = {
  index: number;
  occurrence: OccurrenceInput;
  floraMeasurement: FloraMeasurementBundle | null;
};

export type RowError = {
  index: number;
  issues: { path: string; message: string }[];
};

export type ValidationResult = {
  valid: ValidatedRow[];
  errors: RowError[];
};

export type TargetField = {
  field: string;
  label: string;
  required: boolean;
  category: 'occurrence' | 'measurement';
};
```

### TARGET_FIELDS constant (14 entries):
Required occurrence (4): scientificName, eventDate, decimalLatitude, decimalLongitude
Optional occurrence (6): vernacularName, recordedBy, locality, country, occurrenceRemarks, habitat
Measurement (4): height (totalHeight), dbh, diameter, canopyCover (canopyCoverPercent)

